package com.example.loggingapi.controller;

import com.example.loggingapi.model.ApiResponse;
import com.example.loggingapi.model.HealthResponse;
import com.example.loggingapi.model.MessageRequest;
import jakarta.validation.Valid;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api")
public class ApiController {

    private static final Logger log = LoggerFactory.getLogger(ApiController.class);

    @GetMapping("/health")
    public ResponseEntity<HealthResponse> health() {
        log.info("Received health check request");
        HealthResponse response = new HealthResponse("UP", "Service is running");
        log.info("Health check completed successfully with status={}", response.getStatus());
        return ResponseEntity.ok(response);
    }

    @GetMapping("/greet")
    public ResponseEntity<ApiResponse> greet(@RequestParam(defaultValue = "World") String name) {
        log.info("Received greet request for name={}", name);
        ApiResponse response = new ApiResponse("Hello, " + name + "!");
        log.info("Greet request completed successfully for name={}", name);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/messages")
    public ResponseEntity<ApiResponse> createMessage(@Valid @RequestBody MessageRequest request) {
        log.info("Received createMessage request");
        ApiResponse response = new ApiResponse("Message received: " + request.getMessage());
        log.info("Message created successfully");
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }
}

